import{_ as e,o,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"F12: 研發產出比與技術變現率 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3189_景碩/20260423/F12_研發產出比與技術變現率_投資研究員.md","filePath":"審計報告庫/財務審計/3189_景碩/20260423/F12_研發產出比與技術變現率_投資研究員.md"}'),i={name:"審計報告庫/財務審計/3189_景碩/20260423/F12_研發產出比與技術變現率_投資研究員.md"};function n(l,a,s,_,d,c){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="f12-研發產出比與技術變現率-投資研究員-審計報告" tabindex="-1">F12: 研發產出比與技術變現率 - 投資研究員 審計報告 <a class="header-anchor" href="#f12-研發產出比與技術變現率-投資研究員-審計報告" aria-label="Permalink to &quot;F12: 研發產出比與技術變現率 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>分析景碩近三年研發費用投入與實際營收/獲利產出的關聯性，評估技術轉化效率是否正在改善。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>截至2025年Q4最新數據，研發費用率由9%降至6.5%，營收自80.4億跳增至393.5億，產出倍數由11.4倍升至15.4倍。毛利率同步回升21.1%，每元研發可創1.04元營業利益。變現效率顯著改善，惟費用率壓縮需警惕護城河風險。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：A（良）</strong></p><p>核心數據：2023年研發費用7.04億、營收80.4億、產出倍數11.4x；2024年費用6.78億（偏低，部分歸入製造費用）；2025年費用25.6億、營收393.5億、產出倍數15.4x。每元研發創造3.3元毛利、1.04元營業利益。營收擴張帶動費用槓桿效應，產出效率較2023年提升約35%。惟ABF載板需持續高強度研發投入以維持與欣興、南電的技術距離，未來費用率恐回升至7-8%區間。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>一、研發槓桿深度分析。</strong> 2024年研發費6.78億偏低有其技術背景：載板製程開發直接與產線整合，部分開發成本依IFRS分類標準歸入製造費用（約估2-3億），實質研發投入應約9-10億。以2025年為基準，費用約25.6億（營收6.5%），每元研發創造15.4元營收、3.3元毛利、1.04元營業利益。對比2023年的11.4x產出倍數，效率提升約35%，驅動因子為ABF高階載板放量——ABF單價為BT的3-5倍，同額研發可產出更高附加價值營收。</p><p><strong>二、技術路徑競爭力。</strong> 景碩位居台灣Flip Chip載板市場前三大，CPU載板全球市佔約50%。2025年產品組合：ABF 46%、BT 36%、隱形眼鏡18%，HPC佔營收24%。技術重點：(1) CoWoS載板，與台積電同步開發，2026下半年進入驗證；(2) CPO共封裝光學載板，預計2028年成熟；(3) 高層數ABF（30層以上），滿足AI加速器需求。2026年動能來自Google TPU v6與Meta AI訂單，下半年AWS Trainium 2將供貨，HPC客戶從2家擴至4家，多元性提升。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>（一）槓桿來自景氣復甦與技術轉型疊加。</strong> 載板高固定成本特性顯著：2023年營收80億無法稀釋固定支出；2025年393億後同團隊產出倍數成長。此為營運槓桿與效率提升的雙重疊加，非單純壓縮研發投入。同業對比：欣興研發費用率約7.5%、南電約7.0%，景碩6.5%略低，差距在合理波動內。</p><p><strong>（二）費用率下降的質量解釋。</strong> 比率由8.75%降至6.5%，實為營收增速（389%）遠超研發增速（263%）的數學結果。毛利率同步回升至21.1%證明ABF替代低端BT帶動獲利結構優化，非縮減研發投入。但須追蹤2026年費用率是否隨新製程開發回升。</p><p><strong>（三）華爾街空頭視角。</strong> 三雄處研發軍備競賽，235億CapEx若未轉化為ASIC量產，年增折舊20-30億將壓縮營業利益。T-Glass介電材料由日本Nittobo獨家供應，2027年新產能開出前供應瓶頸將限制ABF擴產速度。若AI需求修正，研發費用從營運槓桿變為不可削減的固定成本，營收退回200-250億區間時費用率將反彈逾10%，形成獲利雙重打擊。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: <code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py finance 3189 2022-01-01 2025-12-31 --df</code> (科目：營業收入、營業成本、營業費用、營業利益)</li><li><code>財報狗網站</code>: statementdog.com/analysis/3189/operating-expense-ratio (2025年Q1-Q4研發費用率)</li><li><code>景碩法說會簡報</code> 2026-03-17 (產品組合、HPC佔比、競爭格局)</li><li><code>經濟日報</code> 2026/03/15 景碩業績發表會報導</li><li><code>理周投研部</code> 2026/03/22 ABF大缺貨分析：ASIC訂單時間表</li></ul>',17)])])}const u=e(i,[["render",n]]);export{p as __pageData,u as default};
